import { _decorator, Component, director, Node, Label, Button, Sprite, Animation, tween, Vec3 } from 'cc';
import { GameManager } from '../Core/GameManager';
import { Utils } from '../Utils/Utils';

const { ccclass, property } = _decorator;

@ccclass('GachaScene')
export class GachaScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    drawOneBtn: Button = null;
    
    @property(Button)
    drawTenBtn: Button = null;
    
    @property(Label)
    costLabel: Label = null;
    
    @property(Label)
    pityLabel: Label = null;
    
    @property(Node)
    resultPanel: Node = null;
    
    @property(Sprite)
    resultIcon: Sprite = null;
    
    @property(Label)
    resultNameLabel: Label = null;
    
    @property(Label)
    resultQualityLabel: Label = null;
    
    @property(Node)
    cardFlipNode: Node = null;
    
    private costPerDraw: number = 60;
    private pityCount: number = 0;
    private maxPity: number = 90;
    
    private rewards = [
        { type: 'god', name: '财神祝福', quality: 'legendary', prob: 0.01, icon: '🎊' },
        { type: 'equipment', name: '传说装备', quality: 'epic', prob: 0.05, icon: '⚔️' },
        { type: 'pet', name: '稀有灵兽', quality: 'rare', prob: 0.15, icon: '🐉' },
        { type: 'item', name: '高级供品', quality: 'uncommon', prob: 0.3, icon: '📿' },
        { type: 'currency', name: '香火钱', quality: 'common', prob: 0.49, amount: 1000, icon: '💰' }
    ];
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.drawOneBtn.node.on(Button.EventType.CLICK, () => this.onDraw(1), this);
        this.drawTenBtn.node.on(Button.EventType.CLICK, () => this.onDraw(10), this);
    }
    
    start() {
        this.updateUI();
    }
    
    updateUI() {
        this.costLabel.string = `${this.costPerDraw}元宝/次`;
        this.pityLabel.string = `保底: ${this.pityCount}/${this.maxPity}`;
    }
    
    onDraw(times: number) {
        const totalCost = this.costPerDraw * times;
        const player = GameManager.getInstance().playerData;
        
        if (!player.costCurrency('yuanbao', totalCost)) {
            console.log('元宝不足');
            return;
        }
        
        // 显示抽卡动画
        this.showDrawAnimation(times);
    }
    
    showDrawAnimation(times: number) {
        // 翻转卡片动画
        this.cardFlipNode.active = true;
        
        tween(this.cardFlipNode)
            .to(0.5, { scale: new Vec3(0.1, 1, 1) })
            .call(() => {
                // 中间帧，切换显示
            })
            .to(0.5, { scale: new Vec3(1, 1, 1) })
            .call(() => {
                this.showResult(times);
            })
            .start();
    }
    
    showResult(times: number) {
        const results = [];
        
        for (let i = 0; i < times; i++) {
            this.pityCount++;
            
            let reward;
            if (this.pityCount >= this.maxPity) {
                // 保底
                reward = this.rewards[0];
                this.pityCount = 0;
            } else {
                // 随机抽取
                const rand = Math.random();
                let cumProb = 0;
                for (const r of this.rewards) {
                    cumProb += r.prob;
                    if (rand <= cumProb) {
                        reward = r;
                        break;
                    }
                }
            }
            
            results.push(reward);
            
            // 发放奖励
            if (reward.type === 'currency') {
                GameManager.getInstance().playerData.addCurrency('incense_money', reward.amount || 1000);
            } else if (reward.type === 'item') {
                GameManager.getInstance().playerData.addCurrency('incense_sticks', 10);
            }
        }
        
        // 显示结果
        this.showResultPanel(results[0]);
        this.updateUI();
    }
    
    showResultPanel(reward: any) {
        this.resultPanel.active = true;
        this.resultNameLabel.string = reward.name;
        this.resultQualityLabel.string = reward.quality;
        this.resultQualityLabel.color = this.getQualityColor(reward.quality);
        
        // 显示图标
        // this.resultIcon.spriteFrame = ...
    }
    
    getQualityColor(quality: string) {
        const colors = {
            common: { r: 149, g: 165, b: 166 },
            uncommon: { r: 46, g: 204, b: 113 },
            rare: { r: 52, g: 152, b: 219 },
            epic: { r: 155, g: 89, b: 182 },
            legendary: { r: 243, g: 156, b: 18 }
        };
        return colors[quality] || colors.common;
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
